/** Strip invalid chars while typing; keep digits, +, spaces, dashes, parentheses. */
export function normalizePhoneInput(value: string): string {
  return value.replace(/[^\d+\-\s()]/g, '').replace(/\s+/g, ' ').trimStart();
}

/** Persistable phone — digits only, optional leading + for international. */
export function normalizePhoneForSave(value?: string | null): string | undefined {
  const raw = value?.trim();
  if (!raw) return undefined;
  const hasPlus = raw.startsWith('+');
  const digits = raw.replace(/\D/g, '');
  if (!digits) return undefined;
  return hasPlus ? `+${digits}` : digits;
}
